#include "layer_norm_custom_tiling.h"
#include "register/op_def_registry.h"
#include <numeric>
#include <vector>

namespace optiling {

// UB budget estimation: each tile needs buffers for x, y, and temporary for stats (sum, sum_sq).
// We need 3 tile buffers (x, y, tmp) => 3 * tile * 4 bytes = 12 * tile bytes.
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  // conservative per-core share
static constexpr uint32_t ALIGN_ELEMS = 2048;            // favor larger DMA bursts
static constexpr uint32_t MIN_TILE_ELEMS = 4096;         // minimum tile size
static constexpr uint32_t MAX_BLOCKS = 24;               // typical for ascend910b

static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    LayerNormCustomTilingData tiling;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const std::vector<int64_t> *normShapePtr = attrs->GetAttrPointer<std::vector<int64_t>>(0);
    const float *epsilon = attrs->GetAttrPointer<float>(1);

    // Compute rowSize = product of normalized_shape
    uint32_t rowSize = 1;
    if (normShapePtr && !normShapePtr->empty()) {
        for (auto s : *normShapePtr) {
            rowSize *= static_cast<uint32_t>(s);
        }
    } else {
        // If not provided, infer from input shape? For simplicity require attribute.
        return ge::GRAPH_FAILED;
    }

    uint32_t totalElements = static_cast<uint32_t>(context->GetInputShape(0)->GetOriginShape().GetShapeSize());
    uint32_t totalRows = totalElements / rowSize;
    if (totalRows == 0 || rowSize == 0) return ge::GRAPH_FAILED;

    // Determine tileLength from UB budget
    uint32_t maxTile = UB_BUDGET_BYTES / (3 * sizeof(float)); // 3 buffers per tile
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < MIN_TILE_ELEMS) maxTile = MIN_TILE_ELEMS;

    uint32_t tileLen = (rowSize < maxTile) ? AlignDown(rowSize, ALIGN_ELEMS) : maxTile;
    if (tileLen < MIN_TILE_ELEMS) tileLen = rowSize; // if rowSize smaller than min, use it directly

    // Set blockDim: one block per row, but cap
    uint32_t blockDim = totalRows;
    if (blockDim > MAX_BLOCKS) blockDim = MAX_BLOCKS;
    if (blockDim < 1) blockDim = 1;

    context->SetBlockDim(blockDim);

    tiling.set_rowSize(rowSize);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_epsilon(*epsilon);
    tiling.set_hasWeight(context->GetInputShape(1) != nullptr);
    tiling.set_hasBias(context->GetInputShape(2) != nullptr);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

namespace ge {
static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::Shape *x_shape = context->GetInputShape(0);
    gert::Shape *y_shape = context->GetOutputShape(0);
    *y_shape = *x_shape;
    return GRAPH_SUCCESS;
}

static ge::graphStatus InferDataType(gert::InferDataTypeContext *context)
{
    const ge::DataType x_dtype = context->GetInputDataType(0);
    context->SetOutputDataType(0, x_dtype);
    // optional weight/bias dtype ignored
    return GRAPH_SUCCESS;
}
} // namespace ge

