#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelLayerNormCustom {
public:
    __aicore__ inline KernelLayerNormCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, GM_ADDR weight, GM_ADDR bias,
                                uint32_t rowSize, uint32_t tileLength,
                                float epsilon, bool hasWeight, bool hasBias)
    {
        xGm_.SetGlobalBuffer((__gm__ float*)x);
        yGm_.SetGlobalBuffer((__gm__ float*)y);
        if (hasWeight) weightGm_.SetGlobalBuffer((__gm__ float*)weight, rowSize);
        if (hasBias)   biasGm_.SetGlobalBuffer((__gm__ float*)bias, rowSize);

        rowSize_ = rowSize;
        tileLen_ = tileLength;
        epsilon_ = epsilon;
        hasWeight_ = hasWeight;
        hasBias_ = hasBias;

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
        // Additional buffer for temporary stats (actually we use scalar variables)
    }

    __aicore__ inline void Process()
    {
        // Each block processes a contiguous range of rows.
        uint32_t blockIdx = AscendC::GetBlockIdx();
        uint32_t blockNum = AscendC::GetBlockNum();
        uint32_t rowsPerBlock = (totalRows_ + blockNum - 1) / blockNum;
        uint32_t startRow = blockIdx * rowsPerBlock;
        uint32_t endRow = (blockIdx + 1) * rowsPerBlock;
        if (endRow > totalRows_) endRow = totalRows_;

        for (uint32_t r = startRow; r < endRow; r++) {
            ProcessRow(r);
        }
    }

private:
    __aicore__ inline void ProcessRow(uint32_t rowIdx)
    {
        uint32_t rowOffset = rowIdx * rowSize_;
        // First pass: compute sum and sum of squares
        float sum = 0.0f;
        float sumSq = 0.0f;
        uint32_t remaining = rowSize_;
        uint32_t offset = rowOffset;

        while (remaining > 0) {
            uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[offset], curLen);

            // Reduce sum
            AscendC::LocalTensor<float> tmp = tmpQueue_.AllocTensor<float>();
            AscendC::ReduceAdd(tmp, xLocal, curLen);
            float tileSum = tmp.GetValue(0);
            sum += tileSum;

            // Reduce sum of squares
            AscendC::Mul(tmp, xLocal, xLocal, curLen);
            AscendC::ReduceAdd(tmp, tmp, curLen);
            float tileSumSq = tmp.GetValue(0);
            sumSq += tileSumSq;

            tmpQueue_.FreeTensor(tmp);
            inQueueX_.FreeTensor(xLocal);

            remaining -= curLen;
            offset += curLen;
        }

        // Compute mean and variance
        float mean = sum / static_cast<float>(rowSize_);
        float var = sumSq / static_cast<float>(rowSize_) - mean * mean;
        if (var < 0.0f) var = 0.0f;
        float invStd = 1.0f / sqrt(var + epsilon_);

        // Second pass: normalize and apply affine
        remaining = rowSize_;
        offset = rowOffset;

        while (remaining > 0) {
            uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[offset], curLen);

            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();

            // y = (x - mean) * invStd
            AscendC::Sub(yLocal, xLocal, mean, curLen);
            AscendC::Mul(yLocal, yLocal, invStd, curLen);

            // Apply weight and bias if present (broadcast over tile)
            if (hasWeight_ || hasBias_) {
                AscendC::LocalTensor<float> wLocal = tmpQueue_.AllocTensor<float>();
                AscendC::LocalTensor<float> bLocal = tmpQueue_.AllocTensor<float>(); // reuse but careful: not simultaneous
                // We'll use separate temporary from pipe if needed, but we can reuse tmpQueue by freeing after.
                // For simplicity, directly use GM reads with local copy if weight/bias present.
                // Since weight and bias are small (rowSize), we can load entire weight/bias once per row.
                // But here we need to load tile-sized portions aligned to tile boundaries.
                // We'll assume weight and bias are contiguous and tileLen divides rowSize.
                // Actually they can be repeated; we'll load the corresponding chunk.
                if (hasWeight_) {
                    // Load the same portion from weight (which has length rowSize)
                    AscendC::LocalTensor<float> wChunk = tmpQueue_.AllocTensor<float>();
                    AscendC::DataCopy(wChunk, weightGm_[offset % rowSize_], curLen);
                    AscendC::Mul(yLocal, yLocal, wChunk, curLen);
                    tmpQueue_.FreeTensor(wChunk);
                }
                if (hasBias_) {
                    AscendC::LocalTensor<float> bChunk = tmpQueue_.AllocTensor<float>();
                    AscendC::DataCopy(bChunk, biasGm_[offset % rowSize_], curLen);
                    AscendC::Add(yLocal, yLocal, bChunk, curLen);
                    tmpQueue_.FreeTensor(bChunk);
                }
            }

            // Write output
            AscendC::DataCopy(yGm_[offset], yLocal, curLen);

            outQueueY_.FreeTensor(yLocal);
            inQueueX_.FreeTensor(xLocal);

            remaining -= curLen;
            offset += curLen;
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;
    AscendC::GlobalTensor<float> weightGm_;
    AscendC::GlobalTensor<float> biasGm_;

    uint32_t rowSize_ {0};
    uint32_t tileLen_ {0};
    uint32_t totalRows_ {0};
    float epsilon_ {1e-5f};
    bool hasWeight_ {false};
    bool hasBias_ {false};
};

extern "C" __global__ __aicore__ void layer_norm_custom(GM_ADDR x, GM_ADDR y, GM_ADDR weight, GM_ADDR bias, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelLayerNormCustom op;
    op.Init(x, y, weight, bias,
            tiling_data.rowSize,
            tiling_data.tileLength,
            tiling_data.epsilon,
            tiling_data.hasWeight,
            tiling_data.hasBias);
    op.Process();
}
