#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"
#include <vector>

at::Tensor layer_norm_impl_npu(
    const at::Tensor& self,
    const c10::optional<at::Tensor>& weight,
    const c10::optional<at::Tensor>& bias,
    const std::vector<int64_t>& normalized_shape,
    double epsilon
) {
    at::Tensor result = at::empty_like(self);
    // Flatten weight and bias if provided
    at::Tensor flatWeight;
    at::Tensor flatBias;
    if (weight.has_value()) {
        flatWeight = weight.value().reshape({-1});
    }
    if (bias.has_value()) {
        flatBias = bias.value().reshape({-1});
    }
    EXEC_NPU_CMD(aclnnLayerNormCustom, self, flatWeight, flatBias, normalized_shape, epsilon, result);
    return result;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("layer_norm_custom", &layer_norm_impl_npu);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("layer_norm_custom", &layer_norm_impl_npu, "Layer Normalization (LayerNormCustom on NPU)",
          py::arg("x"),
          py::arg("weight") = py::none(),
          py::arg("bias") = py::none(),
          py::arg("normalized_shape"),
          py::arg("epsilon") = 1e-5);
}
